import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useCart } from '../../context/CartContext';
import Spinner from '../../components/Spinner';

const API = 'http://localhost:5000/api';

export default function CustomerHome() {
  const [cities, setCities] = useState([]);
  const [selectedCity, setSelectedCity] = useState('');
  const [restaurants, setRestaurants] = useState([]);
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();
  const { fetchCart } = useCart();

  useEffect(() => {
    fetchCities();
    fetchCart();
    // eslint-disable-next-line
  }, []);

  useEffect(() => {
    fetchRestaurants();
    // eslint-disable-next-line
  }, [selectedCity]);

  const fetchCities = async () => {
    try {
      const res = await axios.get(`${API}/restaurants/meta/cities`);
      setCities(res.data);
    } catch (err) {
      console.error(err);
    }
  };

  const fetchRestaurants = async () => {
    setLoading(true);
    try {
      const url = selectedCity
        ? `${API}/restaurants?city=${selectedCity}`
        : `${API}/restaurants`;
      const res = await axios.get(url);
      setRestaurants(res.data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="page-content">
      <div className="container">
        {/* City Filter */}
        <div className="row mb-4 align-items-center">
          <div className="col-md-6">
            <h2 style={{ fontWeight: 700 }}>🍽️ Explore Restaurants</h2>
            <p className="text-muted">Find the best food in your city</p>
          </div>
          <div className="col-md-6">
            <select
              className="form-select form-select-lg"
              value={selectedCity}
              onChange={(e) => setSelectedCity(e.target.value)}
              style={{ borderRadius: '12px' }}
            >
              <option value="">All Cities</option>
              {cities.map((city) => (
                <option key={city} value={city}>{city}</option>
              ))}
            </select>
          </div>
        </div>

        {/* Restaurant List */}
        {loading ? (
          <Spinner />
        ) : restaurants.length === 0 ? (
          <div className="text-center py-5">
            <h4 className="text-muted">No restaurants found</h4>
            <p className="text-muted">Try selecting a different city</p>
          </div>
        ) : (
          <div className="row g-4">
            {restaurants.map((restaurant) => (
              <div key={restaurant._id} className="col-md-4 col-sm-6">
                <div
                  className="card restaurant-card"
                  onClick={() => navigate(`/customer/restaurant/${restaurant._id}`)}
                >
                  {restaurant.image ? (
                    <img
                      src={`http://localhost:5000${restaurant.image}`}
                      alt={restaurant.name}
                      className="card-img-top"
                    />
                  ) : (
                    <div className="card-img-top placeholder-img" style={{ height: 200 }}>
                      {restaurant.name.charAt(0)}
                    </div>
                  )}
                  <div className="card-body">
                    <h5 className="card-title fw-bold">{restaurant.name}</h5>
                    <p className="card-text text-muted" style={{ fontSize: '0.9rem' }}>
                      {restaurant.description?.substring(0, 80)}...
                    </p>
                    <span className="city-badge">📍 {restaurant.city}</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
