import React from 'react';
import { Link } from 'react-router-dom';
import { FiShield, FiClock, FiMapPin, FiStar } from 'react-icons/fi';

export default function LandingPage() {
  return (
    <div className="landing-page">
      <Link to="/admin/login" className="admin-icon-btn">
        <FiShield size={16} />
        Admin Portal
      </Link>

      <div className="landing-hero">
        <h1>Fast Way</h1>
        <p className="landing-subtitle">
          Discover top-rated restaurants near you. Order delicious meals
          delivered fast — all in one beautifully simple app.
        </p>

        <div className="landing-features">
          <div className="landing-feature">
            <div className="landing-feature-icon">
              <FiClock />
            </div>
            <div className="landing-feature-label">Fast Delivery</div>
          </div>
          <div className="landing-feature">
            <div className="landing-feature-icon">
              <FiMapPin />
            </div>
            <div className="landing-feature-label">50+ Cities</div>
          </div>
          <div className="landing-feature">
            <div className="landing-feature-icon">
              <FiStar />
            </div>
            <div className="landing-feature-label">Top Rated</div>
          </div>
        </div>

        <Link to="/login" className="btn-get-started">
          Get Started →
        </Link>
      </div>

      <div className="landing-stats">
        <div className="text-center">
          <div className="landing-stat-value">500+</div>
          <div className="landing-stat-label">Restaurants</div>
        </div>
        <div className="text-center">
          <div className="landing-stat-value">10K+</div>
          <div className="landing-stat-label">Customers</div>
        </div>
        <div className="text-center">
          <div className="landing-stat-value">4.9★</div>
          <div className="landing-stat-label">Rating</div>
        </div>
      </div>
    </div>
  );
}
